SELECT BIN_TO_UUID(grade_updates.id) AS grade_update_id, BIN_TO_UUID(grade_updates.user_id) AS user_id, user_profiles.username AS username, grade_updates.grade_diff, grade_updates.reason, grade_updates.status, grade_updates.created_at, grade_updates.updated_at FROM grade_updates JOIN user_profiles ON grade_updates.user_id = user_profiles.user_id WHERE grade_updates.status = 'pending' ORDER BY grade_updates.created_at ASC;
